import 'dart:convert';

import '../../../../core/protocol/navivox_endpoint_uri.dart';
import '../../../../core/protocol/navivox_json.dart';
import '../../../../core/protocol/navivox_pairing_descriptor.dart';
import '../../models/connection_import.dart';

class ConnectionImportParser {
  const ConnectionImportParser();

  SetupQrImageImport? parsePayload(String payload) {
    final text = payload.trim();
    if (text.isEmpty) return null;

    final jsonResult = _parseQrJsonPayload(text);
    if (jsonResult != null && jsonResult.hasValues) return jsonResult;

    final uri = Uri.tryParse(text);
    if (uri != null && uri.hasScheme) {
      if (_isCorePairingDescriptorUri(uri)) {
        return _parseCorePairingDescriptor(text, uri);
      }

      final uriImport = _importFromGenericUri(uri);
      if (uriImport != null) return uriImport;
    }

    final baseUrl = _normalizeBaseUrl(_firstUrl(text));
    final token = _firstToken(text);
    if (baseUrl != null || token != null) {
      return SetupQrImageImport(baseUrl: baseUrl, token: token);
    }
    return null;
  }

  SetupQrImageImport? _parseCorePairingDescriptor(String text, Uri uri) {
    if (uri.scheme != 'navivox' || uri.host != 'connect') return null;
    try {
      final descriptor = NavivoxPairingDescriptor.parse(text);
      return SetupQrImageImport(
        baseUrl: descriptor.baseUri.toString(),
        token: descriptor.token,
        webSocketUrl: descriptor.webSocketUri.toString(),
        serverId: descriptor.serverId,
        profileId: descriptor.profileId,
      );
    } on FormatException {
      return null;
    }
  }

  SetupQrImageImport? _parseQrJsonPayload(String text) {
    Object? decoded;
    try {
      decoded = jsonDecode(text);
    } catch (_) {
      return null;
    }
    if (decoded is! Map) return null;

    final topLevelImport = _importFromFields(decoded);
    if (topLevelImport != null) return topLevelImport;

    final entries = decoded['entries'];
    if (entries is List) {
      for (final entry in entries) {
        if (entry is! Map) continue;
        final import = _importFromFields(entry);
        if (import != null) return import;
      }
    }
    return null;
  }
}

SetupQrImageImport? parseNavivoxConnectionImportPayload(String payload) =>
    const ConnectionImportParser().parsePayload(payload);

bool _isCorePairingDescriptorUri(Uri uri) =>
    uri.scheme == 'navivox' && uri.host == 'connect';

SetupQrImageImport? _importFromFields(
  Map<dynamic, dynamic> fields, {
  String? fallbackBaseUrl,
}) {
  final token = navivoxFirstStringFieldFromJson(fields, _tokenFieldNames);
  final webSocketUrl = navivoxFirstStringFieldFromJson(
    fields,
    _webSocketUrlFieldNames,
  );
  final explicitBaseUrl =
      _normalizeBaseUrl(
        navivoxFirstStringFieldFromJson(fields, _baseUrlFieldNames),
      ) ??
      _normalizeWebSocketBaseUrl(webSocketUrl);
  final candidate = _ConnectionImportCandidate(
    baseUrl: explicitBaseUrl ?? fallbackBaseUrl,
    token: token,
    webSocketUrl: _normalizeWebSocketUrl(webSocketUrl),
    serverId: navivoxFirstStringFieldFromJson(fields, _serverIdFieldNames),
    profileId: navivoxFirstStringFieldFromJson(fields, _profileIdFieldNames),
  );
  if (!candidate.hasImportValues) return null;

  return candidate.toImport();
}

SetupQrImageImport? _importFromGenericUri(Uri uri) {
  final import = _importFromFields(
    _genericUriFields(uri),
    fallbackBaseUrl: _baseUrlFromGenericUri(uri),
  );
  if (import != null) return import;
  if (uri.scheme == 'http' || uri.scheme == 'https') {
    return SetupQrImageImport(baseUrl: navivoxOriginFromUri(uri));
  }
  if (_isWebSocketUri(uri)) {
    return SetupQrImageImport(
      baseUrl: _webSocketUriBaseUrl(uri),
      webSocketUrl: uri.toString(),
    );
  }
  return null;
}

Map<String, String> _genericUriFields(Uri uri) {
  final fields = Map<String, String>.of(uri.queryParameters);
  if (_isWebSocketUri(uri) &&
      navivoxFirstStringFieldFromJson(fields, _webSocketUrlFieldNames) ==
          null) {
    fields['websocket_url'] = uri.toString();
  }
  return fields;
}

String? _baseUrlFromGenericUri(Uri uri) {
  return switch (uri.scheme) {
    'http' || 'https' => navivoxOriginFromUri(uri),
    'ws' || 'wss' => _webSocketUriBaseUrl(uri),
    _ => null,
  };
}

bool _isWebSocketUri(Uri uri) => uri.scheme == 'ws' || uri.scheme == 'wss';

String? _webSocketUriBaseUrl(Uri uri) {
  try {
    return navivoxHttpBaseUrlFromEndpointUri(uri);
  } on FormatException {
    return null;
  }
}

class _ConnectionImportCandidate {
  const _ConnectionImportCandidate({
    this.baseUrl,
    this.token,
    this.webSocketUrl,
    this.serverId,
    this.profileId,
  });

  final String? baseUrl;
  final String? token;
  final String? webSocketUrl;
  final String? serverId;
  final String? profileId;

  bool get hasImportValues => baseUrl != null || token != null;

  SetupQrImageImport toImport() {
    return SetupQrImageImport(
      baseUrl: baseUrl,
      token: token,
      webSocketUrl: webSocketUrl,
      serverId: serverId,
      profileId: profileId,
    );
  }
}

const _tokenFieldNames = [
  'token',
  'pairing_token',
  'pairingToken',
  'auth_token',
  'rest_token',
  'restToken',
];
const _webSocketUrlFieldNames = [
  'websocket_url',
  'websocketUrl',
  'ws_url',
  'wsUrl',
];
const _baseUrlFieldNames = ['base_url', 'baseUrl', 'gateway_url', 'url'];
const _serverIdFieldNames = ['server_id', 'serverId'];
const _profileIdFieldNames = ['profile_id', 'profileId'];

String? _firstUrl(String text) {
  var value = RegExp(r'https?://\S+').firstMatch(text)?.group(0);
  while (value != null &&
      value.isNotEmpty &&
      ',;)]}"'.contains(value[value.length - 1])) {
    value = value.substring(0, value.length - 1);
  }
  return value;
}

String? _firstToken(String text) {
  final labeledToken = _firstLabeledToken(text);
  if (labeledToken != null) return labeledToken;

  final navivoxIndex = text.toLowerCase().indexOf('nvbx_');
  return navivoxIndex < 0 ? null : _readTokenAt(text, navivoxIndex);
}

String? _firstLabeledToken(String text) {
  for (final label in _tokenLabels) {
    final match = RegExp(
      '${RegExp.escape(label)}\\s*[:=]',
      caseSensitive: false,
    ).firstMatch(text);
    if (match == null) continue;
    final token = _readTokenAt(text, match.end);
    if (token != null) return token;
  }
  return null;
}

const _tokenLabels = [
  'pairing token',
  'pairing_token',
  'pairing-token',
  'auth token',
  'auth_token',
  'auth-token',
  'token',
];

String? _readTokenAt(String text, int start) {
  var index = start;
  while (index < text.length && text.codeUnitAt(index) <= 32) {
    index++;
  }
  final tokenStart = index;
  while (index < text.length && _isTokenChar(text.codeUnitAt(index))) {
    index++;
  }
  if (index == tokenStart) return null;
  return _trimTokenTrailingPunctuation(text.substring(tokenStart, index));
}

String _trimTokenTrailingPunctuation(String token) {
  var end = token.length;
  while (end > 0 && '.,;:!?)]}"\''.contains(token[end - 1])) {
    end--;
  }
  return token.substring(0, end);
}

bool _isTokenChar(int codeUnit) {
  return (codeUnit >= 0x30 && codeUnit <= 0x39) ||
      (codeUnit >= 0x41 && codeUnit <= 0x5a) ||
      (codeUnit >= 0x61 && codeUnit <= 0x7a) ||
      codeUnit == 0x2d ||
      codeUnit == 0x2e ||
      codeUnit == 0x2f ||
      codeUnit == 0x3a ||
      codeUnit == 0x3d ||
      codeUnit == 0x5f ||
      codeUnit == 0x7e ||
      codeUnit == 0x2b;
}

String? _normalizeBaseUrl(String? raw) => navivoxHttpOriginOrOriginalFromString(
  navivoxOptionalLiteralStringFromJson(raw),
);

String? _normalizeWebSocketUrl(String? raw) =>
    navivoxWebSocketUrlFromEndpointString(
      navivoxOptionalLiteralStringFromJson(raw),
    );

String? _normalizeWebSocketBaseUrl(String? raw) =>
    navivoxHttpBaseUrlFromEndpointString(
      navivoxOptionalLiteralStringFromJson(raw),
    );

import '../connection_import_parser.dart';

void main() {
  parsesValidCorePairingDescriptor();
  parsesGenericTokenUrlOutsideCoreDescriptorProtocol();
  preservesGenericUrlMetadataWhenBaseUrlComesFromUrlOrigin();
  preservesGenericWebSocketUrlImports();
  parsesSharedTextTokenWithSpacedSeparator();
  rejectsMalformedCorePairingDescriptorBeforeGenericFallback();
  rejectsCorePairingDescriptorWithHttpWebSocketUrl();
}

void parsesValidCorePairingDescriptor() {
  final result = parseNavivoxConnectionImportPayload(
    'navivox://connect?websocket_url=ws%3A%2F%2F127.0.0.1%3A8765%2Fws&rest_token=nvbx_ok&server_id=srv&profile_id=profile',
  );

  _expect(result != null, 'valid navivox://connect descriptor should parse');
  _expect(
    result!.baseUrl == 'http://127.0.0.1:8765',
    'baseUrl derived from websocket_url',
  );
  _expect(
    result.webSocketUrl == 'ws://127.0.0.1:8765/ws',
    'webSocketUrl preserved',
  );
  _expect(result.token == 'nvbx_ok', 'rest_token preserved');
  _expect(result.serverId == 'srv', 'server_id preserved');
  _expect(result.profileId == 'profile', 'profile_id preserved');
}

void parsesGenericTokenUrlOutsideCoreDescriptorProtocol() {
  final result = parseNavivoxConnectionImportPayload(
    'https://gateway.example/connect?token=nvbx_generic',
  );

  _expect(result != null, 'generic URL import should still parse');
  _expect(
    result!.baseUrl == 'https://gateway.example',
    'generic URL baseUrl normalized',
  );
  _expect(result.token == 'nvbx_generic', 'generic token preserved');
}

void preservesGenericUrlMetadataWhenBaseUrlComesFromUrlOrigin() {
  final result = parseNavivoxConnectionImportPayload(
    'https://gateway.example/connect?server_id=srv&profile_id=profile',
  );

  _expect(result != null, 'generic URL metadata import should parse');
  _expect(
    result!.baseUrl == 'https://gateway.example',
    'URL origin provides baseUrl',
  );
  _expect(result.serverId == 'srv', 'server_id should be preserved');
  _expect(result.profileId == 'profile', 'profile_id should be preserved');
}

void preservesGenericWebSocketUrlImports() {
  final result = parseNavivoxConnectionImportPayload(
    'wss://gateway.example/navivox/ws?token=nvbx_generic',
  );

  _expect(result != null, 'generic websocket URL import should parse');
  _expect(
    result!.baseUrl == 'https://gateway.example',
    'generic websocket URL should derive HTTP baseUrl',
  );
  _expect(
    result.webSocketUrl ==
        'wss://gateway.example/navivox/ws?token=nvbx_generic',
    'generic websocket URL should be preserved',
  );
  _expect(result.token == 'nvbx_generic', 'generic websocket token preserved');
}

void parsesSharedTextTokenWithSpacedSeparator() {
  final result = parseNavivoxConnectionImportPayload(
    'Server: https://gateway.example/connect\nToken = shared_secret',
  );

  _expect(result != null, 'shared text import should parse');
  _expect(
    result!.baseUrl == 'https://gateway.example',
    'shared text URL origin should provide baseUrl',
  );
  _expect(
    result.token == 'shared_secret',
    'token labels should allow spaces before separators',
  );
}

void rejectsMalformedCorePairingDescriptorBeforeGenericFallback() {
  final result = parseNavivoxConnectionImportPayload(
    'navivox://connect?rest_token=nvbx_token_only',
  );

  _expect(
    result == null,
    'malformed navivox://connect descriptors must be rejected instead of '
    'falling back to a token-only generic import',
  );
}

void rejectsCorePairingDescriptorWithHttpWebSocketUrl() {
  final result = parseNavivoxConnectionImportPayload(
    'navivox://connect?websocket_url=https%3A%2F%2Fgateway.example%2Fws&rest_token=nvbx_ok',
  );

  _expect(
    result == null,
    'core pairing websocket_url must be a ws/wss endpoint, not an HTTP URL',
  );
}

void _expect(bool condition, String message) {
  if (!condition) throw StateError(message);
}

// Models for Navivox connection import/pairing handoff payloads.
//
// These value types are shared across the registration, pairing, setup,
// and screens subfolders.

enum PairingHandoffSource { manual, qrImage, sharedText, directAppOpen }

class SetupQrImageImport {
  const SetupQrImageImport({
    this.baseUrl,
    this.token,
    this.webSocketUrl,
    this.serverId,
    this.profileId,
    this.source = PairingHandoffSource.manual,
  });

  final String? baseUrl;
  final String? token;
  final String? webSocketUrl;
  final String? serverId;
  final String? profileId;
  final PairingHandoffSource source;

  bool get hasValues => baseUrl != null || token != null;

  SetupQrImageImport withSource(PairingHandoffSource source) {
    return SetupQrImageImport(
      baseUrl: baseUrl,
      token: token,
      webSocketUrl: webSocketUrl,
      serverId: serverId,
      profileId: profileId,
      source: source,
    );
  }
}

import '../models/connection_import.dart';
import '../shared/connection_import_parser.dart';

/// Parses the platform-channel shape used by Android connect intents.
///
/// Native code may deliver either a plain payload string or a map containing
/// the payload plus handoff provenance metadata.
SetupQrImageImport? parseNavivoxConnectIntentPayload(Object? payload) {
  if (payload is String) {
    final text = payload.trim();
    if (text.isEmpty) return null;
    return parseNavivoxConnectionImportPayload(text);
  }
  if (payload is! Map) return null;
  final text = payload['payload']?.toString().trim();
  if (text == null || text.isEmpty) return null;
  final parsed = parseNavivoxConnectionImportPayload(text);
  if (parsed == null) return null;
  return parsed.withSource(pairingHandoffSourceFromPlatformPayload(payload['source']));
}

PairingHandoffSource pairingHandoffSourceFromPlatformPayload(Object? value) {
  return switch (value?.toString().trim()) {
    'direct_app_open' => PairingHandoffSource.directAppOpen,
    'shared_text' => PairingHandoffSource.sharedText,
    _ => PairingHandoffSource.manual,
  };
}

import '../models/connection_import.dart';
import 'navivox_connect_intent_payload.dart';

void main() {
  parsesPlainStringPayloadAsManualImport();
  preservesMapPayloadSourceProvenance();
  trimsPlatformSourceTokenBeforeMappingProvenance();
}

void parsesPlainStringPayloadAsManualImport() {
  final result = parseNavivoxConnectIntentPayload(
    ' https://gateway.example/connect?token=nvbx_token ',
  );

  _expect(result != null, 'plain string payload should parse');
  _expect(
    result!.baseUrl == 'https://gateway.example',
    'plain string base URL should be derived from URL origin',
  );
  _expect(result.token == 'nvbx_token', 'plain string token should parse');
  _expect(
    result.source == PairingHandoffSource.manual,
    'plain string payloads have no platform provenance metadata',
  );
}

void preservesMapPayloadSourceProvenance() {
  final result = parseNavivoxConnectIntentPayload({
    'payload': 'https://gateway.example/connect?token=nvbx_token',
    'source': 'shared_text',
  });

  _expect(result != null, 'map payload should parse');
  _expect(
    result!.source == PairingHandoffSource.sharedText,
    'shared_text source should be preserved',
  );
}

void trimsPlatformSourceTokenBeforeMappingProvenance() {
  final result = parseNavivoxConnectIntentPayload({
    'payload': 'https://gateway.example/connect?token=nvbx_token',
    'source': ' shared_text ',
  });

  _expect(result != null, 'map payload with padded source should parse');
  _expect(
    result!.source == PairingHandoffSource.sharedText,
    'platform source token should be trimmed before source mapping',
  );
}

void _expect(bool condition, String message) {
  if (!condition) throw StateError(message);
}

/// Shared coercion helpers for Navivox wire-protocol JSON payloads.
///
/// These helpers intentionally accept loose `Object?` values because gateway and
/// memory endpoints can be decoded from typed maps, platform channels, or JSON
/// maps with dynamic keys.
String navivoxStringFromJson(Object? value, {required String fallback}) {
  final text = value?.toString().trim();
  if (text == null || text.isEmpty) return fallback;
  return text;
}

String? navivoxOptionalStringFromJson(Object? value) {
  final text = value?.toString().trim();
  if (text == null || text.isEmpty) return null;
  return text;
}

/// Returns a trimmed string only when [value] is already a literal string.
String? navivoxOptionalLiteralStringFromJson(Object? value) {
  if (value is! String) return null;
  final text = value.trim();
  return text.isEmpty ? null : text;
}

int navivoxIntFromJson(Object? value) {
  if (value is int) return value;
  if (value is num) return value.toInt();
  return int.tryParse(value?.toString() ?? '') ?? 0;
}

double? navivoxDoubleFromJson(Object? value) {
  if (value is double) return value;
  if (value is num) return value.toDouble();
  return double.tryParse(value?.toString() ?? '');
}

bool navivoxBoolFromJson(Object? value, {bool fallback = false}) {
  if (value is bool) return value;
  final text = value?.toString().trim().toLowerCase();
  if (text == 'true' || text == '1' || text == 'yes') return true;
  if (text == 'false' || text == '0' || text == 'no') return false;
  return fallback;
}

/// Returns only literal bool values or `true`/`false` string tokens.
///
/// Use this for protocol flags whose existing contract intentionally does not
/// accept broader truthy aliases such as `1` or `yes`.
bool navivoxStrictBoolFromJson(Object? value, {bool fallback = false}) {
  if (value is bool) return value;
  final text = value?.toString().trim().toLowerCase();
  if (text == 'true') return true;
  if (text == 'false') return false;
  return fallback;
}

Map<String, Object?> navivoxMapFromJson(Object? value) {
  if (value is! Map) return const {};
  return Map<String, Object?>.from(value);
}

Map<String, Object?> navivoxMapFieldFromJson(
  Map<String, Object?> json,
  String key,
) {
  return navivoxMapFromJson(json[key]);
}

List<Object?> navivoxListFromJson(Object? value) {
  if (value is! List) return const [];
  return value.cast<Object?>();
}

/// Returns map entries from a loose wire list, ignoring non-map items.
List<Map<String, Object?>> navivoxMapListFromJson(Object? value) {
  return navivoxListFromJson(
    value,
  ).whereType<Map>().map(navivoxMapFromJson).toList(growable: false);
}

List<Object?> navivoxListFieldFromJson(Map<String, Object?> json, String key) {
  return navivoxListFromJson(json[key]);
}

List<String> navivoxStringListFromJson(Object? value) {
  if (value is! List) return const [];
  return navivoxTrimmedStringList(value);
}

String navivoxStringFieldFromJson(Map<String, Object?> json, String key) {
  return navivoxStringFromJson(json[key], fallback: '');
}

/// Selects a typed enum/value object by matching its wire value.
///
/// The wire token uses the same non-empty trimmed string semantics as other
/// Navivox protocol fields and falls back when the value is blank or unknown.
T navivoxValueFromWire<T>({
  required Object? value,
  required Iterable<T> values,
  required String Function(T value) wireValue,
  required T fallback,
}) {
  final text = navivoxOptionalStringFromJson(value);
  if (text == null) return fallback;
  for (final candidate in values) {
    if (wireValue(candidate) == text) return candidate;
  }
  return fallback;
}

/// Returns the first non-empty literal string field whose key matches [names].
///
/// The lookup first honors exact keys, then falls back to a compatibility match
/// that ignores underscores and case so wire payloads can use either
/// `snake_case` or `camelCase` aliases without each parser reimplementing that
/// policy. Non-string values are intentionally ignored to preserve strict wire
/// semantics for IDs, URLs, and tokens.
String? navivoxFirstStringFieldFromJson(
  Map<dynamic, dynamic> json,
  Iterable<String> names,
) {
  for (final name in names) {
    final exact = navivoxOptionalLiteralStringFromJson(json[name]);
    if (exact != null) return exact;
  }
  final normalizedNames = {
    for (final name in names) _navivoxNormalizeJsonFieldName(name),
  };
  for (final entry in json.entries) {
    if (!normalizedNames.contains(
      _navivoxNormalizeJsonFieldName('${entry.key}'),
    )) {
      continue;
    }
    final value = navivoxOptionalLiteralStringFromJson(entry.value);
    if (value != null) return value;
  }
  return null;
}

String _navivoxNormalizeJsonFieldName(String value) =>
    value.toLowerCase().replaceAll('_', '');

List<String> navivoxStringListFieldFromJson(
  Map<String, Object?> json,
  String key,
) {
  return navivoxStringListFromJson(json[key]);
}

/// Returns non-empty trimmed string values in their original order.
List<String> navivoxTrimmedStringList(Iterable<Object?> values) {
  return values
      .map((item) => item.toString().trim())
      .where((item) => item.isNotEmpty)
      .toList(growable: false);
}

/// Returns a string map with null/blank values removed and remaining values
/// trimmed. Useful for query params and wire request bodies that share Navivox
/// non-empty string field semantics.
Map<String, String> navivoxTrimmedStringFields(Map<String, Object?> values) {
  return {
    for (final entry in values.entries)
      if (entry.value case final value?)
        if (value.toString().trim().isNotEmpty)
          entry.key: value.toString().trim(),
  };
}

DateTime? navivoxDateTimeFromJson(Object? value) {
  final text = value?.toString().trim();
  if (text == null || text.isEmpty) return null;
  return DateTime.tryParse(text);
}

import '../serialization/navivox_json.dart';

/// URI normalization helpers shared by Navivox pairing and setup flows.
const navivoxEndpointSchemes = {'http', 'https', 'ws', 'wss'};

bool navivoxIsEndpointScheme(String scheme) {
  return navivoxEndpointSchemes.contains(scheme.trim().toLowerCase());
}

String navivoxHttpSchemeFromEndpointScheme(
  String scheme, {
  String? descriptor,
}) {
  return switch (scheme.trim().toLowerCase()) {
    'ws' => 'http',
    'wss' => 'https',
    'http' => 'http',
    'https' => 'https',
    _ => throw FormatException(
      'Navivox endpoint URI must use ws, wss, http, or https',
      descriptor,
    ),
  };
}

String navivoxOriginFromUri(Uri uri) {
  final host = uri.host.contains(':') ? '[${uri.host}]' : uri.host;
  final port = uri.hasPort ? ':${uri.port}' : '';
  return '${uri.scheme}://$host$port';
}

String navivoxHttpBaseUrlFromEndpointUri(Uri uri, {String? descriptor}) {
  final scheme = navivoxHttpSchemeFromEndpointScheme(
    uri.scheme,
    descriptor: descriptor,
  );
  if (uri.host.isEmpty) {
    throw FormatException(
      'Navivox endpoint URI must include a host',
      descriptor,
    );
  }
  return navivoxOriginFromUri(uri.replace(scheme: scheme));
}

String? navivoxHttpOriginOrOriginalFromString(String? raw) {
  final value = navivoxOptionalStringFromJson(raw);
  if (value == null) return null;
  final uri = Uri.tryParse(value);
  if (uri == null || !uri.hasScheme || uri.host.isEmpty) return value;
  final scheme = uri.scheme.toLowerCase();
  if (scheme != 'http' && scheme != 'https') return value;
  return navivoxOriginFromUri(uri);
}

Uri navivoxWebSocketUriFromEndpointString(String raw, {String? descriptor}) {
  final uri = Uri.parse(raw);
  if (uri.host.isEmpty) {
    throw FormatException(
      'Navivox websocket URI must include a host',
      descriptor,
    );
  }
  final scheme = uri.scheme.toLowerCase();
  if (scheme != 'ws' && scheme != 'wss') {
    throw FormatException(
      'Navivox websocket URI must use ws or wss',
      descriptor,
    );
  }
  return uri;
}

String? navivoxWebSocketUrlFromEndpointString(String? raw) {
  final value = navivoxOptionalStringFromJson(raw);
  if (value == null) return null;
  try {
    return navivoxWebSocketUriFromEndpointString(value).toString();
  } on FormatException {
    return null;
  }
}

String? navivoxHttpBaseUrlFromEndpointString(String? raw) {
  final uri = _endpointUriFromString(raw);
  if (uri == null || !navivoxIsEndpointScheme(uri.scheme)) return null;
  return navivoxHttpBaseUrlFromEndpointUri(uri);
}

Uri? _endpointUriFromString(String? raw) {
  final value = navivoxOptionalStringFromJson(raw);
  if (value == null) return null;
  final uri = Uri.tryParse(value);
  if (uri == null || !uri.hasScheme || uri.host.isEmpty) return null;
  return uri;
}

import '../../gateway/client/navivox_gateway_config.dart';
import '../endpoint/navivox_endpoint_uri.dart';
import '../serialization/navivox_json.dart';

class NavivoxPairingDescriptor {
  const NavivoxPairingDescriptor({
    required this.baseUri,
    required this.webSocketUri,
    required this.authMode,
    required this.exposureMode,
    required this.tokenRequired,
    this.token,
    this.serverId,
    this.profileId,
    this.workspaceId,
    this.providerId,
    this.channelIds = const [],
  });

  factory NavivoxPairingDescriptor.parse(String value) {
    final uri = Uri.parse(value.trim());
    if (uri.scheme != 'navivox' || uri.host != 'connect') {
      throw FormatException('Expected navivox://connect descriptor', value);
    }
    final query = uri.queryParameters;
    final tokenRequired = _boolFromPairingParam(query['token_required']);
    final token = _optionalPairingParam(query['rest_token']);
    if (tokenRequired && token == null) {
      throw FormatException('Pairing descriptor requires rest_token', value);
    }
    final webSocketUri = navivoxWebSocketUriFromEndpointString(
      _requiredPairingParam(query, 'websocket_url', value),
      descriptor: value,
    );
    final baseUri = Uri.parse(
      _optionalPairingParam(query['base_url']) ??
          _baseUrlFromWebSocketUri(webSocketUri, value),
    );
    return NavivoxPairingDescriptor(
      baseUri: baseUri,
      webSocketUri: webSocketUri,
      authMode: _optionalPairingParam(query['auth_mode']) ?? '',
      exposureMode: _optionalPairingParam(query['exposure_mode']) ?? '',
      tokenRequired: tokenRequired,
      token: token,
      serverId: _optionalPairingParam(query['server_id']),
      profileId: _optionalPairingParam(query['profile_id']),
      workspaceId: _optionalPairingParam(query['workspace_id']),
      providerId: _optionalPairingParam(query['provider_id']),
      channelIds: _csvPairingParam(query['channel_ids']),
    );
  }

  final Uri baseUri;
  final Uri webSocketUri;
  final String authMode;
  final String exposureMode;
  final bool tokenRequired;
  final String? token;
  final String? serverId;
  final String? profileId;
  final String? workspaceId;
  final String? providerId;
  final List<String> channelIds;

  NavivoxGatewayConfig toGatewayConfig() {
    return NavivoxGatewayConfig(
      baseUri: baseUri,
      token: token,
      webSocketUri: webSocketUri,
    );
  }
}

String _requiredPairingParam(
  Map<String, String> query,
  String name,
  String descriptor,
) {
  final value = _optionalPairingParam(query[name]);
  if (value == null) {
    throw FormatException('Pairing descriptor missing $name', descriptor);
  }
  return value;
}

String? _optionalPairingParam(String? value) {
  return navivoxOptionalStringFromJson(value);
}

String _baseUrlFromWebSocketUri(Uri uri, String descriptor) {
  try {
    return navivoxHttpBaseUrlFromEndpointUri(uri, descriptor: descriptor);
  } on FormatException {
    throw FormatException(
      'Pairing descriptor invalid websocket_url',
      descriptor,
    );
  }
}

bool _boolFromPairingParam(String? value) {
  return navivoxStrictBoolFromJson(value);
}

List<String> _csvPairingParam(String? value) {
  final trimmed = navivoxOptionalStringFromJson(value);
  if (trimmed == null) return const [];
  return navivoxTrimmedStringList(trimmed.split(','));
}

